// ──────────────────────────────────────────────────────────
// Master list & helpers
// ──────────────────────────────────────────────────────────
export const ALL_NAMES: BabyName[] = [
  ...WORLDWIDE_NAMES,
  ...EU_NAMES,
  ...US_NAMES,
  ...ARABIA_NAMES,
  ...MENA_NAMES,
  ...ASIA_NAMES,
  ...LATIN_AMERICA_NAMES,
];

export function getNamesByRegion(region: string): BabyName[] {
  if (region === 'WORLDWIDE') return ALL_NAMES;
  return ALL_NAMES.filter(
    (n) => n.region === region || n.is_worldwide
  );
}

export function getRandomNames(count: number, region?: string): BabyName[] {
  const pool = region ? getNamesByRegion(region) : ALL_NAMES;
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}

export function filterByGender(names: BabyName[], gender: string): BabyName[] {
  if (gender === 'both') return names;
  return names.filter((n) => n.gender === gender || n.gender === 'neutral');
}
